#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define Clear(a) memset(a,0,sizeof(a))
#define int long long
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=2e6+10,INF=0x3f3f3f3f;int a[N],p[N][22],L[N];
inline void Init(int mx){rep(1,mx,i)L[i]=L[i>>1]+1;}

signed main()
{
//	freopen("data.txt","r",stdin);freopen("mine.txt","w",stdout);
	int n,m;Init(N-10);while(cin>>n>>m)
	{
		Clear(a);Clear(p);
		rep(1,m,i){int x=read(),y=read();a[x]=max(a[x],x<=y?y:(y+n));}int len=(n<<1);
		int mx=0;rep(1,len,i){mx=max(mx,a[i]);p[i][0]=mx+1;}rep(1,21,i)rep(1,len-(1<<i)+1,j)p[j][i]=p[p[j][i-1]][i-1];
//		rep(1,n,i){rep(0,3,j)printf("%d ",p[i][j]);puts("");}
		int ans=INF;rep(1,n,i)
		{
			int tmp=i,cnt=0;drep(21,0,k){if(p[tmp][k]<=i+n-1&&p[tmp][k])tmp=p[tmp][k],cnt+=pow(2,k);}
			if(p[tmp][0]>i+n-1)ans=min(ans,cnt+1);
		}if(ans==INF)puts("impossible");else printf("%lld\n",ans);
	}
	return 0;
}
